SELECT EXISTS (
    SELECT 1 FROM nextjs_shop_seller
    WHERE seller_id = #{sellerId}
) AS exists_flag

SELECT product_option_id, product_id, add_price, stock, is_displayed, size, sales_count, created_at, updated_at FROM nextjs_shop_product_option WHERE product_id IN
#{id}
ORDER BY product_id, size

mapper.update:
UPDATE nextjs_shop_file f JOIN nextjs_shop_product_image pi ON f.file_id = pi.file_id JOIN nextjs_shop_product p ON pi.product_id = p.product_id SET f.is_deleted = 1, f.deleted_at = CURRENT_TIMESTAMP WHERE f.file_id IN
#{id}
AND p.seller_no = #{sellerNo}

UPDATE nextjs_shop_product_image f
JOIN nextjs_shop_product p ON f.product_id = p.product_id
SET 
	f.sort_key = CASE

			WHEN f.product_image_id = #{item.productImageId} THEN #{item.sortKey}

	END
WHERE 
	f.product_image_id IN

		#{item.productImageId}

	AND p.seller_no = #{sellerNo}

mapper.insert:
INSERT INTO nextjs_shop_product_image(product_id, file_id, sort_key, is_thumbnail)
SELECT #{productId}, #{meta.fileId}, #{meta.sortKey}, #{meta.isThumbnail}
FROM nextjs_shop_product p
WHERE p.product_id = #{productId} AND p.seller_no = #{sellerNo}

