mapper.select:
SELECT DISTINCT pv.user_no
FROM nextjs_shop_product_view pv
JOIN nextjs_shop_product p ON p.product_id = pv.product_id
WHERE p.seller_no = #{sellerNo}
AND NOT EXISTS (
	SELECT 1
	FROM nextjs_shop_user_coupon uc
	WHERE uc.user_no = pv.user_no
	AND uc.coupon_id = #{couponId}
)

SELECT DISTINCT w.user_no
FROM nextjs_shop_wish w
JOIN nextjs_shop_product p ON p.product_id = w.product_id
WHERE p.seller_no = #{sellerNo}
AND NOT EXISTS (
	SELECT 1
	FROM nextjs_shop_user_coupon uc
	WHERE uc.user_no = w.user_no
	AND uc.coupon_id = #{couponId}
)

SELECT DISTINCT bb.user_no
FROM nextjs_shop_brand_bookmark bb
WHERE bb.seller_no = #{sellerNo}
AND NOT EXISTS (
	SELECT 1
	FROM nextjs_shop_user_coupon uc
	WHERE uc.user_no = bb.user_no
	AND uc.coupon_id = #{couponId}
)

SELECT COUNT(DISTINCT pv.user_no)
FROM nextjs_shop_product_view pv
JOIN nextjs_shop_product p ON p.product_id = pv.product_id
WHERE p.seller_no = #{sellerNo}
AND NOT EXISTS (
	SELECT 1
	FROM nextjs_shop_user_coupon uc
	WHERE uc.user_no = pv.user_no
	AND uc.coupon_id = #{couponId}
)

SELECT COUNT(DISTINCT w.user_no)
FROM nextjs_shop_wish w
JOIN nextjs_shop_product p ON p.product_id = w.product_id
WHERE p.seller_no = #{sellerNo}
AND NOT EXISTS (
	SELECT 1
	FROM nextjs_shop_user_coupon uc
	WHERE uc.user_no = w.user_no
	AND uc.coupon_id = #{couponId}
)

SELECT COUNT(DISTINCT bb.user_no)
FROM nextjs_shop_brand_bookmark bb
WHERE bb.seller_no = #{sellerNo}
AND NOT EXISTS (
	SELECT 1
	FROM nextjs_shop_user_coupon uc
	WHERE uc.user_no = bb.user_no
	AND uc.coupon_id = #{couponId}
)
